import{_ as e,o as r,c as p,a2 as o}from"./chunks/framework.N6Nd-M9-.js";const b=JSON.parse('{"title":"企业常识","description":"","frontmatter":{},"headers":[],"relativePath":"notes/企业文化/新人手册/05-企业常识.md","filePath":"notes/企业文化/新人手册/05-企业常识.md"}'),t={name:"notes/企业文化/新人手册/05-企业常识.md"};function a(d,i,n,l,s,x){return r(),p("div",null,[...i[0]||(i[0]=[o('<h1 id="企业常识" tabindex="-1">企业常识 <a class="header-anchor" href="#企业常识" aria-label="Permalink to &quot;企业常识&quot;">​</a></h1><h2 id="公司日常运作流程" tabindex="-1">公司日常运作流程 <a class="header-anchor" href="#公司日常运作流程" aria-label="Permalink to &quot;公司日常运作流程&quot;">​</a></h2><p>掌握企业日常运作的基本常识，帮助你更好地适应工作环境，提高工作效率。</p><p>💡 企业常识是日常工作的基础规范，了解这些规则能让你更快融入团队，避免不必要的失误。</p><p>企业常识看似简单，却是日常工作的基础。</p><div style="display:flex;flex-wrap:wrap;gap:20px;margin:20px 0;"><div style="flex:1;min-width:280px;background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);padding:25px;border-radius:12px;"><p style="font-size:22px;font-weight:bold;margin:0 0 15px 0;color:#667eea;">🌅 早上流程</p><div style="background:rgba(102,126,234,0.08);padding:15px;border-radius:8px;"><p style="margin:0;font-size:15px;line-height:1.8;color:#333;">晨会互动游戏<br>销售&quot;五步&quot;练习、小组会议<br>Impact（销售技巧会议）<br>Meeting（经理分享会议）<br>工作准备、拍档系统的建立</p></div></div><div style="flex:1;min-width:280px;background:rgba(34,197,94,0.06);border:1px solid rgba(34,197,94,0.15);padding:25px;border-radius:12px;"><p style="font-size:22px;font-weight:bold;margin:0 0 15px 0;color:#22c55e;">🌙 晚上流程</p><div style="background:rgba(102,126,234,0.08);padding:15px;border-radius:8px;"><p style="margin:0;font-size:15px;line-height:1.8;color:#333;">组内总结<br>打钟、打锣、打鼓心得分享<br>分批培训、Meeting<br>工作汇总、额外里程</p></div></div></div><h2 id="一周目标" tabindex="-1">一周目标 <a class="header-anchor" href="#一周目标" aria-label="Permalink to &quot;一周目标&quot;">​</a></h2><div style="background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);padding:25px;border-radius:12px;margin:20px 0;"><p style="font-size:20px;font-weight:bold;margin:0 0 15px 0;color:#667eea;">🎯 目标的意义</p><p style="margin:0 0 15px 0;font-size:15px;line-height:1.7;color:#333;">所有成功人士都有一个突出特征—目标的确定和有效计划的实施。制定一周目标有助于小伙伴们评估工作的进展，提高工作效率。一周目标，既是激励也是鞭策。</p><div style="display:flex;flex-wrap:wrap;gap:10px;margin-bottom:15px;"><span style="background:rgba(102,126,234,0.1);padding:8px 15px;border-radius:20px;font-size:14px;color:#667eea;">📌 核心目标</span><span style="background:rgba(102,126,234,0.1);padding:8px 15px;border-radius:20px;font-size:14px;color:#667eea;">📚 学习目标</span><span style="background:rgba(102,126,234,0.1);padding:8px 15px;border-radius:20px;font-size:14px;color:#667eea;">🔄 改进目标</span><span style="background:rgba(102,126,234,0.1);padding:8px 15px;border-radius:20px;font-size:14px;color:#667eea;">⚡ 执行目标</span><span style="background:rgba(102,126,234,0.1);padding:8px 15px;border-radius:20px;font-size:14px;color:#667eea;">🏷️ 队名队号</span><span style="background:rgba(102,126,234,0.1);padding:8px 15px;border-radius:20px;font-size:14px;color:#667eea;">📊 效果跟踪</span></div><div style="background:rgba(102,126,234,0.08);padding:15px;border-radius:8px;"><p style="margin:0;font-size:14px;line-height:1.7;color:#333;"><strong>💡 使用方法：</strong>每周末团队总结时，团队成员应携带个人周目标参与团队会议，汇报个人周目标执行程度与效果，并阐述过程中期望得到的帮助与鼓励；在团队负责人指导下，对下一周的目标进行规划与更新。</p></div></div><h2 id="黄金计划" tabindex="-1">黄金计划 <a class="header-anchor" href="#黄金计划" aria-label="Permalink to &quot;黄金计划&quot;">​</a></h2><p>  早上，有针对性地练习五步，并且做好学以致用的准备。</p><p>  重视早晚黄金时间的参与。主动学习，清楚自己的学习方向；以系统为基础，重视个人的成长。</p><p>  晚上，总结好的方面；通过数据发现了什么？明天计划和达成措施？</p><div style="display:flex;flex-wrap:wrap;align-items:center;justify-content:center;gap:15px;margin:25px 0;"><div style="background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);padding:25px 30px;border-radius:16px;text-align:center;min-width:150px;"><p style="margin:0;font-size:28px;">🔧</p><p style="margin:10px 0 0 0;font-size:18px;font-weight:bold;color:#667eea;">复杂的事</p><p style="margin:5px 0 0 0;font-size:22px;font-weight:bold;color:#333;">简单做</p></div><div style="font-size:28px;color:#667eea;">→</div><div style="background:rgba(34,197,94,0.06);border:1px solid rgba(34,197,94,0.15);padding:25px 30px;border-radius:16px;text-align:center;min-width:150px;"><p style="margin:0;font-size:28px;">🔄</p><p style="margin:10px 0 0 0;font-size:18px;font-weight:bold;color:#22c55e;">简单的事</p><p style="margin:5px 0 0 0;font-size:22px;font-weight:bold;color:#333;">重复做</p></div><div style="font-size:28px;color:#22c55e;">→</div><div style="background:rgba(239,68,68,0.06);border:1px solid rgba(239,68,68,0.15);padding:25px 30px;border-radius:16px;text-align:center;min-width:150px;"><p style="margin:0;font-size:28px;">💖</p><p style="margin:10px 0 0 0;font-size:18px;font-weight:bold;color:#ef4444;">重复的事</p><p style="margin:5px 0 0 0;font-size:22px;font-weight:bold;color:#333;">用心做</p></div></div><div style="background:rgba(249,115,22,0.08);border:1px solid rgba(249,115,22,0.15);padding:15px 20px;border-radius:10px;text-align:center;margin-top:15px;font-size:15px;color:#f97316;"><p style="margin:0;font-weight:bold;">💡 核心理念：把每一件平凡的事做到极致，就是不平凡！</p></div><h2 id="打钟分享" tabindex="-1">打钟分享 <a class="header-anchor" href="#打钟分享" aria-label="Permalink to &quot;打钟分享&quot;">​</a></h2><div style="background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);padding:25px;border-radius:12px;margin:20px 0;"><div style="display:flex;flex-wrap:wrap;gap:12px;"><div style="flex:1;min-width:200px;background:rgba(102,126,234,0.08);padding:15px;border-radius:8px;"><p style="margin:0;font-size:18px;font-weight:bold;color:#667eea;">1️⃣ 回到公司第一时间打钟</p></div><div style="flex:1;min-width:200px;background:rgba(102,126,234,0.08);padding:15px;border-radius:8px;"><p style="margin:0;font-size:18px;font-weight:bold;color:#667eea;">2️⃣ 敲大声一点、时间长一点</p><p style="margin:5px 0 0 0;font-size:13px;color:#333;">敲到接待室和经理办公室门口。</p></div><div style="flex:1;min-width:200px;background:rgba(102,126,234,0.08);padding:15px;border-radius:8px;"><p style="margin:0;font-size:18px;font-weight:bold;color:#667eea;">3️⃣ 敲钟时要有激情</p><p style="margin:5px 0 0 0;font-size:13px;color:#333;">兴奋、有感染力</p></div><div style="flex:1;min-width:200px;background:rgba(102,126,234,0.08);padding:15px;border-radius:8px;"><p style="margin:0;font-size:18px;font-weight:bold;color:#667eea;">4️⃣ 上台分享声音洪亮</p><p style="margin:5px 0 0 0;font-size:13px;color:#333;">要有激情和气势</p></div><div style="flex:1;min-width:200px;background:rgba(102,126,234,0.08);padding:15px;border-radius:8px;"><p style="margin:0;font-size:18px;font-weight:bold;color:#667eea;">5️⃣ 分享前做好准备</p><p style="margin:5px 0 0 0;font-size:13px;color:#333;">内容积极、正面、简单、明了</p></div><div style="flex:1;min-width:200px;background:rgba(102,126,234,0.08);padding:15px;border-radius:8px;"><p style="margin:0;font-size:18px;font-weight:bold;color:#667eea;">6️⃣ 懂得推广赚钱和作业乐趣</p></div><div style="flex:1;min-width:200px;background:rgba(102,126,234,0.08);padding:15px;border-radius:8px;"><p style="margin:0;font-size:18px;font-weight:bold;color:#667eea;">7️⃣ 设定次日目标</p></div></div></div><h2 id="为什么要拿独立编号" tabindex="-1">为什么要拿独立编号 <a class="header-anchor" href="#为什么要拿独立编号" aria-label="Permalink to &quot;为什么要拿独立编号&quot;">​</a></h2><div style="display:flex;flex-wrap:wrap;gap:15px;margin:20px 0;"><div style="flex:1;min-width:220px;background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);padding:20px;border-radius:12px;"><p style="font-size:32px;margin:0 0 10px 0;">🏅</p><p style="font-size:16px;font-weight:bold;margin:0;color:#667eea;">新人正式成为同创人的标志</p></div><div style="flex:1;min-width:220px;background:rgba(34,197,94,0.06);border:1px solid rgba(34,197,94,0.15);padding:20px;border-radius:12px;"><p style="font-size:32px;margin:0 0 10px 0;">🤝</p><p style="font-size:16px;font-weight:bold;margin:0;color:#22c55e;">证明新人和公司同进步、共发展的个人意愿</p></div><div style="flex:1;min-width:220px;background:rgba(239,68,68,0.06);border:1px solid rgba(239,68,68,0.15);padding:20px;border-radius:12px;"><p style="font-size:32px;margin:0 0 10px 0;">💪</p><p style="font-size:16px;font-weight:bold;margin:0;color:#ef4444;">证明新人能够适应市场，有足够的生存能力</p></div><div style="flex:1;min-width:220px;background:rgba(59,130,246,0.06);border:1px solid rgba(59,130,246,0.15);padding:20px;border-radius:12px;"><p style="font-size:32px;margin:0 0 10px 0;">✨</p><p style="font-size:16px;font-weight:bold;margin:0;color:#3b82f6;">证明新人的个人形象符合集团基本形象的标准</p></div></div><h2 id="预备主管的晋升条件" tabindex="-1">预备主管的晋升条件 <a class="header-anchor" href="#预备主管的晋升条件" aria-label="Permalink to &quot;预备主管的晋升条件&quot;">​</a></h2><div style="display:flex;flex-wrap:wrap;gap:15px;margin:20px 0;"><div style="flex:1;min-width:180px;background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);padding:20px;border-radius:12px;text-align:center;"><p style="font-size:28px;margin:0 0 8px 0;">🔔</p><p style="font-size:16px;font-weight:bold;margin:0;color:#667eea;">打钟</p></div><div style="flex:1;min-width:180px;background:rgba(34,197,94,0.06);border:1px solid rgba(34,197,94,0.15);padding:20px;border-radius:12px;text-align:center;"><p style="font-size:28px;margin:0 0 8px 0;">❤️</p><p style="font-size:16px;font-weight:bold;margin:0;color:#22c55e;">对企业文化认可</p></div><div style="flex:1;min-width:180px;background:rgba(239,68,68,0.06);border:1px solid rgba(239,68,68,0.15);padding:20px;border-radius:12px;text-align:center;"><p style="font-size:28px;margin:0 0 8px 0;">🔥</p><p style="font-size:16px;font-weight:bold;margin:0;color:#ef4444;">强烈的企图心</p></div><div style="flex:1;min-width:180px;background:rgba(59,130,246,0.06);border:1px solid rgba(59,130,246,0.15);padding:20px;border-radius:12px;text-align:center;"><p style="font-size:28px;margin:0 0 8px 0;">👔</p><p style="font-size:16px;font-weight:bold;margin:0;color:#3b82f6;">专业形象</p></div><div style="flex:1;min-width:180px;background:rgba(249,115,22,0.06);border:1px solid rgba(249,115,22,0.15);padding:20px;border-radius:12px;text-align:center;"><p style="font-size:28px;margin:0 0 8px 0;">🛠️</p><p style="font-size:16px;font-weight:bold;margin:0;color:#f97316;">主动解决问题</p></div><div style="flex:1;min-width:180px;background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);padding:20px;border-radius:12px;text-align:center;"><p style="font-size:28px;margin:0 0 8px 0;">⭐</p><p style="font-size:16px;font-weight:bold;margin:0;color:#667eea;">关键时刻关键表现</p></div><div style="flex:1;min-width:180px;background:rgba(34,197,94,0.06);border:1px solid rgba(34,197,94,0.15);padding:20px;border-radius:12px;text-align:center;"><p style="font-size:28px;margin:0 0 8px 0;">🧠</p><p style="font-size:16px;font-weight:bold;margin:0;color:#22c55e;">正面思维能力</p></div></div><h2 id="家庭日与感恩日" tabindex="-1">家庭日与感恩日 <a class="header-anchor" href="#家庭日与感恩日" aria-label="Permalink to &quot;家庭日与感恩日&quot;">​</a></h2><div style="display:flex;flex-wrap:wrap;gap:20px;margin:20px 0;"><div style="flex:1;min-width:280px;background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);padding:25px;border-radius:12px;"><p style="font-size:22px;font-weight:bold;margin:0 0 15px 0;color:#667eea;">🏠 家庭日</p><p style="margin:0 0 15px 0;font-size:14px;line-height:1.7;color:#333;">每周三，特别是晚餐时间，团队所有&quot;家庭成员&quot;聚在一起，把酒言欢，侃侃而谈。我们分享个人心得与成长过程；也交流上半周遇到的快乐与失意，更彼此鼓励，互加力量；确定下半周的目标与计划，传递热爱与勇气。</p><div style="background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;text-align:center;"><p style="margin:0;font-size:16px;font-weight:bold;color:#667eea;">🥂 &quot;juice&quot;一下，&quot;家庭日快乐&quot;！</p></div></div><div style="flex:1;min-width:280px;background:rgba(34,197,94,0.06);border:1px solid rgba(34,197,94,0.15);padding:25px;border-radius:12px;"><p style="font-size:22px;font-weight:bold;margin:0 0 15px 0;color:#22c55e;">🙏 感恩日</p><p style="margin:0 0 15px 0;font-size:14px;line-height:1.7;color:#333;">周五的感恩日，不仅仅是提醒我们知恩、感恩、施恩，更是企业文化&quot;凡事感激&quot;的践行日。在市场运作中，我们经历着成长过程中的打击、难堪等负面，但因着感恩我们反而更加坚强。因为见不同的人，开拓了眼界，磨练了心志，丰富了阅历，所有挫折最终都变作成功的垫脚石！</p><div style="background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;text-align:center;"><p style="margin:0;font-size:16px;font-weight:bold;color:#22c55e;">💝 &quot;juice&quot;一下，&quot;感恩日惜福&quot;！</p></div></div></div><h2 id="创悦荟" tabindex="-1">创悦荟 <a class="header-anchor" href="#创悦荟" aria-label="Permalink to &quot;创悦荟&quot;">​</a></h2><div style="background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);padding:25px;border-radius:12px;margin:20px 0;"><p style="font-size:20px;font-weight:bold;margin:0 0 15px 0;color:#667eea;">📚 创悦荟</p><p style="margin:0;font-size:15px;line-height:1.7;color:#333;">《创悦荟》是由集团企宣部和商学院共同策划出版，2016年5月创刊。作为同创主悦文化建设和传播的重要工具，是外界了解同创主悦发展动态的媒介，也是集团与分公司之间交流的纽带，更是小伙伴们呈现才艺与创意、展现个人风采、展示成长轨迹的载体。</p></div><h2 id="企业标识" tabindex="-1">企业标识 <a class="header-anchor" href="#企业标识" aria-label="Permalink to &quot;企业标识&quot;">​</a></h2><div style="display:flex;flex-wrap:wrap;gap:20px;margin:20px 0;"><div style="flex:1;min-width:280px;background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);padding:25px;border-radius:12px;"><p style="font-size:22px;font-weight:bold;margin:0 0 15px 0;color:#667eea;">📛 名称：同创主悦</p><p style="margin:0 0 15px 0;font-size:15px;line-height:1.7;color:#333;">共同创造一家让上帝满意喜悦的企业，这个名字有3层含义：</p><div style="display:flex;flex-direction:column;gap:10px;"><div style="background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;"><p style="margin:0;font-size:14px;color:#333;"><strong>1️⃣ 顾客就是上帝</strong><br>做为一家以&quot;成就顾客&quot;为使命的企业，让顾客得到满意的服务是我们做事的第一要素。</p></div><div style="background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;"><p style="margin:0;font-size:14px;color:#333;"><strong>2️⃣ 让自己的价值最大化</strong><br>是自己可以当家做主。&quot;成就自己&quot;也是我们的企业使命之一。</p></div><div style="background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;"><p style="margin:0;font-size:14px;color:#333;"><strong>3️⃣ 对标准和要求有敬畏的人</strong><br>总会得到更多，我们共同努力，让命运之神更多施恩！</p></div></div></div><div style="flex:1;min-width:280px;background:rgba(34,197,94,0.06);border:1px solid rgba(34,197,94,0.15);padding:25px;border-radius:12px;"><p style="font-size:22px;font-weight:bold;margin:0 0 15px 0;color:#22c55e;">🎨 LOGO 寓意</p><div style="display:flex;flex-direction:column;gap:10px;"><div style="background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;"><p style="margin:0;font-size:14px;color:#333;"><strong>💡 意</strong><br>圆周率π是无限小数，在同创主悦的发展无限、你的可能无限！</p></div><div style="background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;"><p style="margin:0;font-size:14px;color:#333;"><strong>🔷 形</strong><br>TC组合而成的π，美好生活是靠&quot;共同&quot;&quot;创新&quot;、&quot;共同&quot;&quot;创造&quot;！</p></div><div style="background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;"><p style="margin:0;font-size:14px;color:#333;"><strong>✏️ 画</strong><br>四笔分别代表一线小伙伴们、核心骨干、职业经理人、集团创始人，小伙伴们永远是第一位！</p></div><div style="background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;"><p style="margin:0;font-size:14px;color:#333;"><strong>🌊 色</strong><br>海蓝色为主色调，代表同创主悦海纳百川的胸怀；边缘处是天蓝色，代表后续发展是比海宽、如天广的格局。</p></div></div></div></div><h2 id="企业歌" tabindex="-1">企业歌 <a class="header-anchor" href="#企业歌" aria-label="Permalink to &quot;企业歌&quot;">​</a></h2><div style="background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);padding:25px;border-radius:12px;margin:20px 0;"><p style="font-size:20px;font-weight:bold;margin:0 0 15px 0;color:#667eea;">🎵 企业歌：《兄弟 抱一下》</p><p style="margin:0 0 20px 0;font-size:14px;line-height:1.7;color:#333;">由同创主悦集团出品、顶级团队打造，于2018年1月登陆各大音乐网站。歌词中蕴含着同创主悦的使命与价值观，旋律间流淌着同创人充沛的激情与生命力；唱的是肝胆相照的兄弟情，颂的是生命不息、奋斗不止的拼搏与奋进。</p><div style="background:rgba(102,126,234,0.08);padding:20px;border-radius:8px;text-align:center;"><p style="margin:0 0 8px 0;font-size:15px;line-height:1.8;font-style:italic;color:#333;">在同创主悦的世界里</p><p style="margin:0 0 8px 0;font-size:15px;line-height:1.8;font-style:italic;color:#333;">你就这样的出现</p><p style="margin:0 0 8px 0;font-size:15px;line-height:1.8;font-style:italic;color:#333;">我回过头 你的笑容就看见</p><p style="margin:0 0 8px 0;font-size:15px;line-height:1.8;font-style:italic;color:#333;">在充满激情的天空下</p><p style="margin:0 0 8px 0;font-size:15px;line-height:1.8;font-style:italic;color:#333;">兄弟顶天又立地 携手并肩</p><p style="margin:0 0 8px 0;font-size:15px;line-height:1.8;font-style:italic;color:#333;">呼风唤雨是兄弟</p><p style="margin:0 0 12px 0;font-size:15px;line-height:1.8;font-style:italic;color:#333;">一杯酒 热血上心头</p><p style="margin:0 0 8px 0;font-size:15px;line-height:1.8;font-style:italic;color:#333;">我们的情谊 高如山 深如海</p><p style="margin:0 0 8px 0;font-size:15px;line-height:1.8;font-style:italic;color:#333;">一杯酒 永生做朋友</p><p style="margin:0 0 12px 0;font-size:15px;line-height:1.8;font-style:italic;color:#333;">我们兄弟情 如烈酒 情长在</p><p style="margin:0 0 8px 0;font-size:14px;line-height:1.8;color:#666;">（一杯酒 热血上心头<br>刀山与火海 好兄弟一起走<br>一杯酒 永生做朋友<br>心跳多久就做多久）</p><p style="margin:0 0 8px 0;font-size:15px;line-height:1.8;font-style:italic;color:#333;">兄弟抱一下 为岁月的牵挂</p><p style="margin:0 0 8px 0;font-size:15px;line-height:1.8;font-style:italic;color:#333;">兄弟抱一下 未来的路不惧怕</p><p style="margin:0 0 8px 0;font-size:15px;line-height:1.8;font-style:italic;color:#333;">一起抱一下 共同见证中国同创</p><p style="margin:0;font-size:15px;line-height:1.8;font-style:italic;color:#333;">中国梦 同创梦 牵手创辉煌</p></div></div><h2 id="同创杯篮球赛" tabindex="-1">同创杯篮球赛 <a class="header-anchor" href="#同创杯篮球赛" aria-label="Permalink to &quot;同创杯篮球赛&quot;">​</a></h2><div style="background:rgba(239,68,68,0.06);border:1px solid rgba(239,68,68,0.15);padding:25px;border-radius:12px;margin:20px 0;"><p style="font-size:20px;font-weight:bold;margin:0 0 15px 0;color:#ef4444;">🏀 同创杯篮球赛</p><p style="margin:0;font-size:15px;line-height:1.7;color:#333;">&quot;同创杯&quot;篮球赛是同创主悦企业文化中&quot;运动精神&quot;的融合落地项目。这个属于所有同创人的大型赛事，由副总裁担纲球协主席组织举办，并由来自全国分公司的漂亮小姐姐们自发组成拉拉队助力参与。在丰富小伙伴们业余生活的同时，更为企业中的广大篮球爱好者们，提供了一个面向全国展现个人魅力的舞台。</p></div><h2 id="商学院" tabindex="-1">商学院 <a class="header-anchor" href="#商学院" aria-label="Permalink to &quot;商学院&quot;">​</a></h2><div style="background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);padding:25px;border-radius:12px;margin:20px 0;"><p style="font-size:20px;font-weight:bold;margin:0 0 15px 0;color:#667eea;">🎓 同创主悦商学院</p><p style="margin:0 0 20px 0;font-size:14px;line-height:1.7;color:#333;">直属于集团理事会的专职培育机构，核心功能为：解决企业一切的培训需求；考核、选拔企业所需要的人才；与时俱进地给予新方向、新技能的带领。按照&quot;开放式培训&quot;模式，运用&quot;以人为本&quot;的实效培训手段，商学院旨在通过企业文化的导入与职业素养的培育，形成&quot;打造合格企业人&quot;的智慧平台，最终成为为集团规划与战略目标服务、推动集团快速稳健倍增发展的赋能组织。</p><div style="display:flex;flex-wrap:wrap;gap:15px;"><div style="flex:1;min-width:180px;background:rgba(102,126,234,0.08);padding:15px;border-radius:8px;text-align:center;"><p style="font-size:24px;margin:0 0 8px 0;">🔭</p><p style="font-size:14px;font-weight:bold;margin:0 0 5px 0;color:#667eea;">愿景</p><p style="margin:0;font-size:13px;color:#333;">让更多人因我们而成就</p></div><div style="flex:1;min-width:180px;background:rgba(102,126,234,0.08);padding:15px;border-radius:8px;text-align:center;"><p style="font-size:24px;margin:0 0 8px 0;">📋</p><p style="font-size:14px;font-weight:bold;margin:0 0 5px 0;color:#667eea;">宗旨</p><p style="margin:0;font-size:13px;color:#333;">严谨 务实 负责 创新 成就</p></div><div style="flex:1;min-width:180px;background:rgba(102,126,234,0.08);padding:15px;border-radius:8px;text-align:center;"><p style="font-size:24px;margin:0 0 8px 0;">👥</p><p style="font-size:14px;font-weight:bold;margin:0 0 5px 0;color:#667eea;">人力资源理念</p><p style="margin:0;font-size:13px;color:#333;">让每个人的价值最大化<br>形成多效益利益共同体<br>共创共赢共享价值</p></div></div></div><h2 id="_15年目标" tabindex="-1">15年目标 <a class="header-anchor" href="#_15年目标" aria-label="Permalink to &quot;15年目标&quot;">​</a></h2><div style="background:rgba(249,115,22,0.08);border:1px solid rgba(249,115,22,0.15);padding:25px;border-radius:12px;margin:20px 0;"><p style="font-size:20px;font-weight:bold;margin:0 0 15px 0;color:#f97316;">🎯 15年目标</p><p style="margin:0 0 15px 0;font-size:15px;line-height:1.7;color:#333;">国家有发展计划，企业也有自己的发展蓝图。同创主悦的十五年目标不仅是对集团目标和方向的规划，更是对小伙伴们发展道路与美好前程的筹划。</p><div style="background:rgba(102,126,234,0.08);padding:15px;border-radius:8px;"><p style="margin:0;font-size:16px;font-weight:bold;text-align:center;color:#333;">同创主悦未来一定会成为百亿、千亿级的企业，帮助更多的人成功，万人成为百万富翁；千人成为千万富翁；百人成为亿万富翁。</p></div></div><h2 id="誓言" tabindex="-1">誓言 <a class="header-anchor" href="#誓言" aria-label="Permalink to &quot;誓言&quot;">​</a></h2><div style="background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);padding:30px;border-radius:12px;margin:20px 0;"><p style="font-size:20px;font-weight:bold;margin:0 0 15px 0;color:#667eea;">宣誓词</p><p style="margin:0 0 20px 0;font-size:14px;line-height:1.7;color:#333;">企业誓言代表着一个企业的整体价值取向，是企业文化的一种体现形式。同创主悦的誓言蕴含着同创主悦集团&quot;同心同行、共享共赢&quot;的人才观与价值观，也是集团发展不可缺少、具有纲领性与指引性的灯塔。</p><div style="background:rgba(102,126,234,0.08);padding:20px;border-radius:8px;border-left:4px solid #667eea;"><p style="margin:0;font-size:16px;line-height:1.8;font-style:italic;text-align:center;color:#333;">作为同创主悦的联合创始人，不论遇到任何困难和挫折，我们都将倾尽全力把同创主悦做大做强，有福同享，有难共担，绝不退缩，共同完成同创大业！</p></div></div>',36)])])}const f=e(t,[["render",a]]);export{b as __pageData,f as default};
